    private String username;
    private String role;
}

Create com.loanflow.identity.dto.auth.LoginResponseDto:

@Getter
@Builder
@NoArgsConstructor
@AllArgsConstructor
public class LoginResponseDto {
    private String accessToken;
    private String tokenType;
    private long expiresIn;
    private UserSummaryDto user;
}

Create com.loanflow.identity.service.AuthService as a Java interface:

public interface AuthService {
    LoginResponseDto login(LoginRequestDto request);
}

Create com.loanflow.identity.service.impl.AuthServiceImpl annotated with @Service:

@Service
@RequiredArgsConstructor
public class AuthServiceImpl implements AuthService {

    @Override
    public LoginResponseDto login(LoginRequestDto request) {
        return LoginResponseDto.builder()
            .accessToken("stub-access-token")
            .tokenType("Bearer")
            .expiresIn(3600)
            .user(UserSummaryDto.builder()
                .id(102L)
                .username(request.getUsername())
                .role("LOAN_OFFICER")
                .build())
            .build();
    }
}

The stub echoes the submitted username in the user summary so the response is traceable to the input.

Create com.loanflow.identity.controller.AuthController:

@RestController
@RequestMapping("/api/v1/auth")
@RequiredArgsConstructor
public class AuthController {

    private final AuthService authService;

    @PostMapping("/login")
    public ResponseEntity<LoginResponseDto> login(
            @RequestBody @Valid LoginRequestDto request) {
        return ResponseEntity.ok(authService.login(request));
    }
}

Create com.loanflow.identity.exception.GlobalExceptionHandler annotated with @RestControllerAdvice. Use Spring's built-in ProblemDetail (org.springframework.http.ProblemDetail) as the response body — no custom error class needed.

Handle the following exception types:

1. MethodArgumentNotValidException → 400 Bad Request
   Collect all field violation messages into a comma-separated string and set as the detail:

   @ExceptionHandler(MethodArgumentNotValidException.class)
   public ProblemDetail handleValidation(MethodArgumentNotValidException ex, HttpServletRequest request) {
       String detail = ex.getBindingResult().getFieldErrors().stream()
           .map(fe -> fe.getField() + ": " + fe.getDefaultMessage())
           .collect(Collectors.joining(", "));
       ProblemDetail pd = ProblemDetail.forStatusAndDetail(HttpStatus.BAD_REQUEST, detail);
       pd.setTitle("Validation Failed");
       pd.setInstance(URI.create(request.getRequestURI()));
       return pd;
   }

2. Exception (catch-all) → 500 Internal Server Error with detail 'An unexpected error occurred'
